+import java.io.StringReader;
+import junit.framework.TestCase;
+
+public class InterpreterAgentTest extends TestCase {
+
+  private Interpreter interp(String program) {
+    return new Interpreter(new StringReader(program));
+  }
+
+  public void testLazyEvaluationSkipsUnusedArgument() {
+    String program = "(map x,y to x)(1, 1 / 0)";
+
+    try {
+      interp(program).callByValue();
+      fail("callByValue should force the second argument");
+    } catch (EvalException e) {
+      // expected
+    }
+
+    assertEquals("1", interp(program).callByName().toString());
+    assertEquals("1", interp(program).callByNeed().toString());
+  }
+
+  public void testLazyBindingsUseLexicalScope() {
+    String program =
+      "let x := 10; " +
+      "    f := map y to let x := 20; in y + 1; " +
+      "in f(x)";
+
+    assertEquals("11", interp(program).callByValue().toString());
+    assertEquals("11", interp(program).callByName().toString());
+    assertEquals("11", interp(program).callByNeed().toString());
+  }
+
+  public void testValueYFactorial() {
+    String program =
+      "let Y := map f to let g := map x to f(map z to (x(x))(z)); in g(g); " +
+      "    FACT := map f to map n to if n = 0 then 1 else n * f(n - 1); " +
+      "in (Y(FACT))(6)";
+
+    assertEquals("720", interp(program).callByValue().toString());
+  }
+
+  public void testNameAndNeedYFactorial() {
+    String program =
+      "let Y := map f to let g := map x to f(x(x)); in g(g); " +
+      "    FACT := map f to map n to if n = 0 then 1 else n * f(n - 1); " +
+      "in (Y(FACT))(6)";
+
+    assertEquals("720", interp(program).callByName().toString());
+    assertEquals("720", interp(program).callByNeed().toString());
+  }
+
+  public void testPrimitiveFunctionsAndLists() {
+    String program =
+      "let xs := cons(1, cons(2, empty)); " +
+      "in cons(arity(cons), " +
+      "   cons(arity(map x,y to x), " +
+      "   cons(function?(map x to x), " +
+      "   cons(list?(xs), " +
+      "   cons(cons?(xs), " +
+      "   cons(empty?(rest(rest(xs))), empty))))))";
+
+    assertEquals("(2 2 true true true true)", interp(program).callByValue().toString());
+    assertEquals("(2 2 true true true true)", interp(program).callByName().toString());
+    assertEquals("(2 2 true true true true)", interp(program).callByNeed().toString());
+  }
+}
